import React, { useState } from 'react';
import FileUpload from './components/FileUpload';



const annex3Questions = [
    {
        question: 'Is Background (existing knowledge) of TNO required to achieve the TNO Results or do you (basically) start from scratch? If yes, please describe/specify the Background.',
        answer: ''
    },
    {
        question: 'Does TNO have the required access rights to the needed Background? In other words: is TNO not limited to use and give access rights to its Background due to other contractual obligations (e.g. licenses)?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to TNO Background for the implementation of the Project?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to TNO Background to be able to use their Results after the Project?',
        answer: ''
    },
    {
        question: 'Does TNO need access rights to Background or Results of partners for the implementation of the Project?',
        answer: ''
    },
    {
        question: 'What will be the Results (in terms of IPR/Foreground) for TNO?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to the TNO Results to be able to use their Results of the project after the Project?',
        answer: ''
    },
    {
        question: 'Will TNO realize the Results on its own or will other Partners also create and own part of these Results (resulting in Joint IP)? Please specify.',
        answer: ''
    },
    {
        question: 'Will the TNO Results be able to operate on itself after the project or is access to Background or Results of other Partners necessary to be able to use these Results?',
        answer: ''
    },
];

const App: React.FC = () => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    // In a real app, answers would be set after processing the file
    const [answers, setAnswers] = useState(annex3Questions);
    const [openIndexes, setOpenIndexes] = useState<number[]>([]);

    const toggleOpen = (idx: number) => {
        setOpenIndexes((prev) =>
            prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
        );
    };

    const handleFileSelected = (file: File) => {
        setSelectedFile(file);
        // setAnswers([]); // Reset or trigger processing here
    };

    return (
        <div className="min-h-screen bg-slate-900 flex flex-col">
            <main className="flex-1 flex flex-col items-center px-4 py-8">
                {/* Header - Centered */}
                <div className="w-full max-w-2xl flex flex-col items-center mb-8">
                    <img src="/logo192.png" alt="EPIFs Assistant Logo" className="w-12 h-12 mb-3" />
                    <h1 className="text-2xl font-bold text-white">EPIFs Assistant</h1>
                    <p className="text-sm text-slate-300 mt-2 text-center">Upload your document and get instant answers</p>
                </div>

                {/* Upload Card - Centered */}
                <div className="w-full max-w-2xl">
                    <div className="bg-slate-800 rounded-lg border border-slate-700 p-6 mb-8">
                        <FileUpload onFileSelected={handleFileSelected} selectedFile={selectedFile} setSelectedFile={setSelectedFile} />
                        {selectedFile && (
                            <button
                                className="mt-4 w-full py-2 px-4 rounded-md bg-indigo-600 hover:bg-indigo-700 text-white font-medium text-sm transition-colors"
                                disabled={false}
                            >
                                Analyse
                            </button>
                        )}
                    </div>

                    {/* Questions - Centered */}
                    {selectedFile && (
                        <div>
                            <h2 className="text-xs font-semibold text-slate-300 uppercase tracking-wider mb-4">Annex 3 Questions</h2>
                            <div className="flex flex-col gap-3">
                                {answers.map((item, idx) => {
                                    const isOpen = openIndexes.includes(idx);
                                    return (
                                        <div
                                            key={idx}
                                            className="bg-slate-800 border border-slate-700 rounded-md p-4 cursor-pointer hover:border-slate-600 transition-colors"
                                            onClick={() => toggleOpen(idx)}
                                            tabIndex={0}
                                            onKeyDown={e => (e.key === 'Enter' || e.key === ' ') && toggleOpen(idx)}
                                            role="button"
                                            aria-expanded={isOpen}
                                        >
                                            <div className="flex items-start justify-between gap-3">
                                                <span className="text-sm text-slate-200 flex-1">{item.question}</span>
                                                <span className="text-indigo-400 text-lg flex-shrink-0">{isOpen ? '−' : '+'}</span>
                                            </div>
                                            {isOpen && (
                                                <div className="mt-3 pt-3 border-t border-slate-700 text-sm text-slate-300">
                                                    {selectedFile ? item.answer || <span className="text-slate-500">(No answer)</span> : <span className="text-slate-500">(Will appear)</span>}
                                                </div>
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    )}
                </div>
            </main>

            {/* Footer */}
            <footer className="text-center py-4 px-4 text-slate-500 text-xs border-t border-slate-700">
                © {new Date().getFullYear()} EPIFs Assistant
            </footer>
        </div>
    );
};

export default App;
